#include<bits/stdc++.h>
using namespace std;
long long n,q,k,root,d[100010];
long long fa[100010][31],lg[100010],cnt[100010],dis[100010],sum;
bool flag[100010];
vector<pair<long long,long long>> mp[100010];
void dfs(long long x,long long f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    if(flag[x])
    {
        cnt[x]=1;
    }
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            dis[v]=dis[x]+val;
            dfs(v,x);
            cnt[x]+=cnt[v];
        }
    }
}
void dfs1(long long x,long long f=-1)
{
    if(!cnt[x])
    {
        return;
    }
    flag[x]=true;
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            dfs1(v,x);
            sum+=flag[v]*val;
        }
    }
}
long long find(long long x)
{
    if(flag[x])
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]&&!flag[fa[x][i]])
        {
            x=fa[x][i];
        }
    }
    return fa[x][0];
}
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
long long dist(long long x,long long y)
{
    return dis[x]+dis[y]-dis[lca(x,y)]*2;
}
int main()
{
    scanf("%lld%lld%lld",&n,&q,&k);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    for(long long i=1;i<=k;i++)
    {
        long long x;
        scanf("%lld",&x);
        flag[x]=1;
        root=x;
    }
    dfs(root);
    dfs1(root);
    while(q--)
    {
        long long s,t,u,v;
        scanf("%lld%lld",&s,&t);
        u=find(s),v=find(t);
        printf("%lld\n",sum*2-dist(u,v)+dist(s,u)+dist(v,t));
    }
    return 0;
}
